const content =
$json.output?.[0]?.content?.[0]?.text ||
$json.output_text ||
$json.text ||
$json.message?.content ||
$json.choices?.[0]?.message?.content ||
"Transcript not found";

const formatted = content

// Section headings
.replace(/^TITLE/gm,"")
.replace(/^OVERVIEW/gm,"<h2>Overview</h2>")
.replace(/^KEY CONCEPTS/gm,"<h2>Key Concepts</h2>")
.replace(/^DETAILED EXPLANATION/gm,"<h2>Detailed Explanation</h2>")
.replace(/^IMPORTANT POINTS/gm,"<h2>Important Points</h2>")
.replace(/^ACTION ITEMS/gm,"<h2>Action Items</h2>")
.replace(/^CONCLUSION/gm,"<h2>Conclusion</h2>")

// Bold sections
.replace(/\*\*(.*?)\*\*/g,"<span class='subheading'>$1</span>")

// Bullets
.replace(/^- /gm,"• ")

.replace(/\n/g,"<br/>");


const html = `
<!DOCTYPE html>
<html>

<head>

<meta charset="UTF-8"/>

<style>

@page{
size:A4;
margin:50px;

@bottom-center{
content:"Page " counter(page) " of " counter(pages);
font-size:11px;
color:#777;
}

}

body{
font-family:Segoe UI,Roboto,Arial;
color:#2d3748;
line-height:1.7;
}

.container{
max-width:850px;
margin:auto;
}

/* cover */

.cover{
text-align:center;
margin-top:180px;
page-break-after:always;
}

.cover h1{
font-size:42px;
margin-bottom:20px;
}

.cover p{
font-size:18px;
color:#666;
}

/* toc */

.toc{
page-break-after:always;
}

.toc h2{
border-bottom:2px solid #4f46e5;
padding-bottom:8px;
}

.toc ul{
list-style:none;
padding-left:0;
}

.toc li{
padding:6px 0;
font-size:16px;
}

/* headings */

h1{
font-size:32px;
margin-bottom:25px;
border-bottom:3px solid #4f46e5;
padding-bottom:10px;
}

h2{
font-size:24px;
margin-top:40px;
margin-bottom:15px;
color:#4f46e5;
}

.subheading{
display:block;
background:#f5f7ff;
border-left:4px solid #4f46e5;
padding:8px 12px;
margin-top:18px;
margin-bottom:10px;
font-weight:600;
}

/* paragraphs */

p{
margin:12px 0;
text-align:justify;
}

/* footer */

.footer{
margin-top:50px;
border-top:1px solid #eee;
padding-top:15px;
font-size:12px;
color:#777;
text-align:center;
}

</style>

</head>

<body>


<div class="cover">

<h1>Meeting Documentation</h1>

<p>Structured notes generated from meeting transcript</p>

<p>${new Date().toLocaleDateString()}</p>

</div>


<div class="toc">

<h2>Table of Contents</h2>

<ul>
<li>Overview</li>
<li>Key Concepts</li>
<li>Detailed Explanation</li>
<li>Important Points</li>
<li>Action Items</li>
<li>Conclusion</li>
</ul>

</div>


<div class="container">

<h1>Meeting Report</h1>

<p>${formatted}</p>

<div class="footer">
Generated automatically from meeting transcript
</div>

</div>


</body>
</html>
`;

return [
{
json:{
html
}
}
];
